def run_gen_logic(chat_id, message_id, uid, casino, game, provider):
    if (time.time() - user_sessions[uid].get("last_gen_time", 0)) < 20:
        bot.send_message(chat_id, "⚠️ SYSTEM BUSY. Pattern is active.\nPlease wait a few seconds...")
        return

    user_sessions[uid]["last_gen_time"] = time.time()
    
    # NOTIFY ADMIN OF GENERATION
    try:
        bot.send_message(ADMIN_ID, f"📊 <b>SIGNAL GENERATED</b>\nUser: {uid}\n🏛 <b>Casino:</b> {casino}\n🎰 <b>Game:</b> {game}", parse_mode="HTML")
    except: pass

    steps = [
        {"icon": "📡", "text": "Connecting to Servers..."},
        {"icon": "🧬", "text": "Extracting RNG Seed Data..."},
        {"icon": "🛰", "text": "Matching Pattern Database..."},
        {"icon": "🧠", "text": "Neural Network Processing..."},
        {"icon": "✅", "text": "Signal Generation Complete!"}
    ]

    for idx, step in enumerate(steps):
        p_bar = ["■" if i <= int((idx/4)*9) else "▯" for i in range(10)]
        status_text = (
            f"<b>{step['icon']} <code>{step['text']}</code></b>\n"
            f"<code>[{''.join(p_bar)}] {int((idx/4)*100)}%</code>"
        )
        try:
            bot.edit_message_text(status_text, chat_id, message_id, parse_mode="HTML")
            time.sleep(0.7)
        except: pass

    try: bot.delete_message(chat_id, message_id)
    except: pass

    # Delete last generated messages
    if user_sessions[uid].get("last_msg"):
        try: bot.delete_message(chat_id, user_sessions[uid]["last_msg"])
        except: pass
    if user_sessions[uid].get("last_kb_msg"):
        try: bot.delete_message(chat_id, user_sessions[uid]["last_kb_msg"])
        except: pass

    ph_now = datetime.utcnow() + timedelta(hours=8)
    v_until = (ph_now + timedelta(minutes=random.randint(30, 45))).strftime("%I:%M %p")

    fake_id = str(uuid.uuid4())[:8].upper()

    if "PG" in provider.upper():
        valid_signals = [s for s in SIGNALS if "Turbo" not in s]
    else:
        valid_signals = SIGNALS
    
    if not valid_signals:
        valid_signals = SIGNALS
    
    result_text = (
        f"📡 <b>SIGNAL DETECTED</b> <code>#{fake_id}</code>\n"
        f"━━━━━━━━━━━━━━━━━━━━━━\n"
        f"🎯 <b>Target:</b> {game}\n"
        f"🎰 <b>Provider:</b> {provider}\n"
        f"📊 <b>Probability:</b> {random.uniform(96, 99):.2f}%\n"
        f"⚡ <b>Volatility:</b> <tg-spoiler>HIGH</tg-spoiler>\n"
        f"🔐 <b>Server Hash:</b> <code>{str(uuid.uuid4())[:16]}...</code>\n"
        f"⏰ <b>Valid Until:</b> {v_until}\n"
        f"━━━━━━━━━━━━━━━━━━━━━━\n"
        f"💡 <i>Click the button below to reveal the injection pattern.</i>"
    )

    user_sessions[uid]["result_text"] = result_text
    user_sessions[uid]["pattern"] = random.choice(valid_signals)
    user_sessions[uid]["encoding"] = True 
    session_id = str(uuid.uuid4())
    user_sessions[uid]["encoding_id"] = session_id
    
    # Inline buttons for everything
    inline_kb = types.InlineKeyboardMarkup(row_width=1)
    inline_kb.add(
        types.InlineKeyboardButton("👁️ SHOW PATTERN", callback_data="show_pattern"),
        types.InlineKeyboardButton("🔄 Re-Generate Pattern", callback_data="run_gen"),
        types.InlineKeyboardButton("🎰 Change Game", callback_data="change_game"),
        types.InlineKeyboardButton("🏛 Change Platform", callback_data="change_platform"),
        types.InlineKeyboardButton("🔄 Reset System", callback_data="reset_system")
    )
    
    # Remove any lingering ReplyKeyboardMarkup
    remove_kb = types.ReplyKeyboardRemove()
    
    # Send message with all inline buttons and remove old keyboard
    msg = bot.send_message(chat_id, result_text, reply_markup=inline_kb, parse_mode="HTML")
    
    # Send a hidden message to remove the keyboard, then delete it
    del_msg = bot.send_message(chat_id, "⚙️ Updating controls...", reply_markup=remove_kb)
    try: bot.delete_message(chat_id, del_msg.message_id)
    except: pass
    
    user_sessions[uid]["last_msg"] = msg.message_id
    user_sessions[uid]["last_kb_msg"] = None # No separate keyboard message

    # Start the live encoding animation thread
    t = threading.Thread(target=live_encoding_animation, args=(chat_id, msg.message_id, uid, casino, session_id))
    t.daemon = True
    t.start()

@bot.callback_query_handler(func=lambda c: c.data == "run_gen")
def run_gen(call):
    uid = call.from_user.id
    
    # Check if we are regenerating from an existing message
    # If so, we want to show the initialization animation first
    if call.message.text and "SIGNAL DETECTED" in call.message.text:
        try: bot.delete_message(call.message.chat.id, call.message.message_id)
        except: pass
        msg = bot.send_message(call.message.chat.id, "🔄 <b>INITIALIZING...</b>\n<code>[▯▯▯▯▯▯▯▯▯▯] 0%</code>", parse_mode="HTML")
        message_id = msg.message_id
    else:
        message_id = call.message.message_id
        
    run_gen_logic(
        call.message.chat.id, 
        message_id, 
        uid, 
        user_sessions[uid].get("casino", "UNKNOWN"), 
        user_sessions[uid].get("game", "UNKNOWN"), 
        user_sessions[uid].get("provider", "UNKNOWN")
    )

if __name__ == "__main__":
    keep_alive()
    bot.remove_webhook()
    time.sleep(1)
    print("🚀 BOT STARTING...")
    while True:
        try:
            bot.polling(none_stop=True, interval=1, timeout=20)
        except Exception as e:
            print(f"Error: {e}")
            time.sleep(5)


# ================= OVERRIDDEN LOGIC FOR MULTI-CASINO PROVIDERS =================
def display_provider_games(chat_id, uid, provider_name):
    user_sessions[uid]["provider"] = provider_name
    selected_casino = user_sessions[uid].get("casino")
    games_list = PROVIDERS_DATA.get(selected_casino, {}).get(provider_name, [])
    # games_list is now a list of dicts like {"n": "Game", "bb": 1}
    display_names = [g["n"] for g in games_list]

    kb = types.ReplyKeyboardMarkup(resize_keyboard=True, row_width=2)
    kb.add(types.KeyboardButton("🔙 BACK"))
    kb.add(*[types.KeyboardButton(n) for n in display_names])

    msg = bot.send_message(chat_id, f"🎰 <b>{provider_name}</b>\nShowing {len(display_names)} Games Available:", reply_markup=kb, parse_mode="HTML")
    user_sessions[uid]["last_msg"] = msg.message_id

def main_menu(chat_id, uid):
    delete_user_past_msg(chat_id, uid)
    
    selected_casino = user_sessions[uid].get("casino")
    providers_list = list(PROVIDERS_DATA.get(selected_casino, {}).keys())
    
    kb = types.ReplyKeyboardMarkup(resize_keyboard=True, row_width=2)
    kb.add(*[types.KeyboardButton(p) for p in providers_list])
    msg = bot.send_message(chat_id, "⚙️ <b>MAIN CONTROL PANEL:</b>\n━━━━━━━━━━━━━━━━━━━━━━\nSelect your preferred Slot Provider to begin analysis:", reply_markup=kb, parse_mode="HTML")
    if uid not in user_sessions:
        user_sessions[uid] = {"last_msg": None, "last_gen_time": 0, "game": None, "provider": None, "encoding": False, "casino": selected_casino}
    user_sessions[uid]["last_msg"] = msg.message_id
    user_sessions[uid]["encoding"] = False

def run_gen_logic(chat_id, message_id, uid, casino, game_name, provider):
    if (time.time() - user_sessions[uid].get("last_gen_time", 0)) < 20:
        bot.send_message(chat_id, "⚠️ SYSTEM BUSY. Pattern is active.\nPlease wait a few seconds...")
        return

    user_sessions[uid]["last_gen_time"] = time.time()
    
    # Notify Admin
    try: bot.send_message(ADMIN_ID, f"📊 <b>SIGNAL GENERATED</b>\nUser: {uid}\n🏛 <b>Casino:</b> {casino}\n🎰 <b>Game:</b> {game_name}", parse_mode="HTML")
    except: pass

    # Find if game has Buy Bonus
    has_bb = False
    provider_games = PROVIDERS_DATA.get(casino, {}).get(provider, [])
    for g in provider_games:
        if g["n"] == game_name:
            has_bb = (g.get("bb", 0) == 1)
            break

    # Filtering signals
    if has_bb:
        # Include Buy Bonus signals
        valid_signals = SIGNALS
    else:
        # Exclude Buy Bonus signals
        valid_signals = [s for s in SIGNALS if "Buy Bonus" not in s]
    
    if "PG" in provider.upper():
        valid_signals = [s for s in valid_signals if "Turbo" not in s]
    
    if not valid_signals: valid_signals = SIGNALS

    # ... remaining generation logic (same but uses valid_signals)
    ph_now = datetime.utcnow() + timedelta(hours=8)
    v_until = (ph_now + timedelta(minutes=random.randint(30, 45))).strftime("%I:%M %p")
    fake_id = str(uuid.uuid4())[:8].upper()

    user_sessions[uid]["result_text"] = f"📡 <b>SIGNAL DETECTED</b> <code>#{fake_id}</code>\n━━━━━━━━━━━━━━━━━━━━━━\n🎯 <b>Target:</b> {game_name}\n🎰 <b>Provider:</b> {provider}\n📊 <b>Probability:</b> {random.uniform(96, 99):.2f}%\n⚡ <b>Volatility:</b> <tg-spoiler>HIGH</tg-spoiler>\n⏰ <b>Valid Until:</b> {v_until}\n━━━━━━━━━━━━━━━━━━━━━━\n💡 <i>Click reveal button below.</i>"
    user_sessions[uid]["pattern"] = random.choice(valid_signals)
    user_sessions[uid]["encoding"] = True 
    session_id = str(uuid.uuid4())
    user_sessions[uid]["encoding_id"] = session_id

    inline_kb = types.InlineKeyboardMarkup(row_width=1)
    inline_kb.add(types.InlineKeyboardButton("👁️ SHOW PATTERN", callback_data="show_pattern"), types.InlineKeyboardButton("🔄 Re-Generate Pattern", callback_data="run_gen"), types.InlineKeyboardButton("🎰 Change Game", callback_data="change_game"), types.InlineKeyboardButton("🏛 Change Platform", callback_data="change_platform"))
    
    bot.send_message(chat_id, user_sessions[uid]["result_text"], reply_markup=inline_kb, parse_mode="HTML")
    threading.Thread(target=live_encoding_animation, args=(chat_id, user_sessions[uid]["last_msg"], uid, casino, session_id)).start()

@bot.message_handler(func=lambda m: m.text in [g["n"] for g in PROVIDERS_DATA.get(user_sessions.get(m.from_user.id, {}).get("casino", ""), {}).get(user_sessions.get(m.from_user.id, {}).get("provider", ""), [])])
def pick_game(message):
    uid = message.from_user.id
    try: bot.delete_message(message.chat.id, message.message_id)
    except: pass
    delete_user_past_msg(message.chat.id, uid)
    user_sessions[uid]["game"] = message.text
    kb = types.InlineKeyboardMarkup().add(types.InlineKeyboardButton("🚀 ANALYZE RNG SEED", callback_data="run_gen"))
    msg = bot.send_message(message.chat.id, f"🎯 <b>SELECTED:</b> {message.text}\nClick below to start RNG sync.", reply_markup=kb, parse_mode="HTML")
    user_sessions[uid]["last_msg"] = msg.message_id

@bot.message_handler(func=lambda m: m.text in PROVIDERS_DATA.get(user_sessions.get(m.from_user.id, {}).get("casino", ""), {}).keys())
def show_games(message):
    uid = message.from_user.id
    try: bot.delete_message(message.chat.id, message.message_id)
    except: pass
    delete_user_past_msg(message.chat.id, uid)
    display_provider_games(message.chat.id, uid, message.text)